section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/cog-walk-process.json",
  "title": "Cognitive Walkthrough: Process",
  "type": "object",
  "required": [
    "artefact_id",
    "prerequisites",
    "evaluators",
    "evaluation_forms",
    "issues",
    "prioritized_findings",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "prerequisites": {
      "type": "object",
      "description": "persona + task + action sequence + interface"
    },
    "evaluators": {
      "type": "array",
      "description": "2-4 named evaluators + role",
      "minItems": 1
    },
    "evaluation_forms": {
      "type": "array",
      "description": "per-evaluator per-step Q1..Q4 forms",
      "minItems": 1
    },
    "issues": {
      "type": "array",
      "description": "{step, severity, fix, evaluator_consensus}",
      "minItems": 1
    },
    "prioritized_findings": {
      "type": "array",
      "description": "ordered fixes with rationale",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
